import{C as t}from"./content-B6ZnHsOX.js";document.title=t.siteTitle;document.getElementById("back-link").innerHTML=t.contact.backLabel;const m=document.getElementById("contact-links");t.links.forEach(n=>{const e=document.createElement("a");e.href=n.url,e.target="_blank",e.innerHTML="&#x2197;&#xFE0E; "+n.label,m.appendChild(e)});document.getElementById("contact-image").alt=t.contact.imageAlt;document.getElementById("contact-note").textContent=t.contact.note;const o=document.getElementById("footer"),l=document.createElement("h2");l.className="reveal reveal-delay-3";const a=document.createElement("a");a.href="mailto:"+t.email;a.target="_blank";a.innerHTML="&#x2197;&#xFE0E; "+t.email;l.appendChild(a);o.appendChild(l);const c=document.createElement("h2");c.className="reveal reveal-delay-4";c.textContent=t.year;o.appendChild(c);const r=new IntersectionObserver(n=>{n.forEach(e=>{e.isIntersecting&&(e.target.classList.add("visible"),r.unobserve(e.target))})},{threshold:.15});document.querySelectorAll(".reveal").forEach(n=>r.observe(n));
